    /**
     * Check if a chunk exists on the network.
     */
    func chunkExists(addressHex: String) async throws  -> Bool
    
    /**
     * Retrieve a chunk by hex-encoded address.
     */
    func chunkGet(addressHex: String) async throws  -> Data
    
    /**
     * Store a chunk on the network.
     */
    func chunkPut(data: Data) async throws  -> ChunkPutResult
    
    /**
     * Retrieve private data using a hex-encoded data map.
     */
    func dataGetPrivate(dataMapHex: String) async throws  -> Data
    
    /**
     * Retrieve public data by hex-encoded address.
     */
    func dataGetPublic(addressHex: String) async throws  -> Data
    
